@app.command()
def convert(
    epub_path: Path = typer.Argument(..., help="Path to the EPUB file to convert."),
) -> None:
    """Convert an EPUB to MP3 chapters. (Milestone 2 — not yet implemented.)"""
    _err_console.print("[yellow]convert command not yet implemented (Milestone 2)[/yellow]")
    raise typer.Exit(code=1)

current_hash = config_hash(settings)
if current_hash == manifest.config_hash:
    return []

# Identify which keys changed
current_snapshot = settings.model_dump(mode="json")
old_snapshot = manifest.config_snapshot
changed_keys = [
    key
    for key in set(current_snapshot) | set(old_snapshot)
    if current_snapshot.get(key) != old_snapshot.get(key)
]
return sorted(changed_keys)
